use std::fmt::Display;

fn print_largest<T: PartialOrd + Display>(list: &[T]) -> &T {
    let mut largest = &list[0];
    for item in list.iter() {
        if item > largest {
            largest = item;
        }
    }
    println!("Largest: {largest}");
    largest
}

fn main() {
    let numbers = vec![34, 50, 25, 100, 65];
    print_largest(&numbers); // monomorphized to i32 at compile time

    let chars = vec!['y', 'm', 'a', 'q'];
    print_largest(&chars); // separate monomorphized version for char
}

fn main() {
    // Stack allocated — dropped when `x` goes out of scope
    let x: i32 = 42;

    // Heap allocated — Box<T> owns the allocation
    let boxed: Box<i32> = Box::new(100);

    // Borrow: read-only reference, no ownership transfer
    let r: &i32 = &x;
    println!("ref: {r}");

    // Exclusive mutable borrow
    let mut v: Vec<i32> = vec![1, 2, 3];
    let first: &mut i32 = &mut v[0];
    *first += 10;
    println!("{:?}", v); // [11, 2, 3]

    // `boxed` and `v` dropped here — heap freed, no GC needed
}

