use criterion::{black_box, criterion_group, criterion_main, Criterion};

fn sum_iterators(data: &[u64]) -> u64 {
    data.iter().sum()
}

fn sum_manual(data: &[u64]) -> u64 {
    let mut acc = 0u64;
    for &x in data { acc += x; }
    acc
}

fn bench_sums(c: &mut Criterion) {
    let data: Vec<u64> = (0..10_000).collect();
    c.bench_function("iter_sum", |b| b.iter(|| sum_iterators(black_box(&data))));
    c.bench_function("manual_sum", |b| b.iter(|| sum_manual(black_box(&data))));
}

criterion_group!(benches, bench_sums);
criterion_main!(benches);

use std::collections::HashMap;
use rustc_hash::FxHashMap; // cargo add rustc-hash

fn main() {
    // std HashMap — DoS-resistant (SipHash), slightly slower
    let mut std_map: HashMap<&str, u32> = HashMap::new();
    std_map.insert("latency_ms", 42);

    // FxHashMap — faster, not cryptographically safe
    let mut fast_map: FxHashMap<&str, u32> = FxHashMap::default();
    fast_map.insert("latency_ms", 42);

    // Same trait-based API — swap without changing call sites
    println!("{:?}", fast_map.get("latency_ms"));
}

