use std::collections::HashMap;
use std::sync::{Arc, RwLock};

// Shared, thread-safe cache — zero GC pressure
type Cache = Arc<RwLock<HashMap<String, Vec<u8>>>>;

async fn fetch_or_cache(cache: Cache, key: &str) -> Vec<u8> {
    if let Some(hit) = cache.read().unwrap().get(key) {
        return hit.clone();
    }
    let value = expensive_fetch(key).await;
    cache.write().unwrap().insert(key.to_owned(), value.clone());
    value
}

async fn expensive_fetch(_key: &str) -> Vec<u8> { vec![] }

struct Parser {
    buf: Vec<u8>,
    pos: usize,
}

impl Parser {
    // Fails: `&mut self` borrows all of `self`,
    // so `self.buf` and `self.pos` can't be re-borrowed
    // fn advance(&mut self) -> u8 { consume(&self.buf, &mut self.pos) }
}

// Fix: free function takes disjoint refs — checker can verify non-aliasing
fn advance(buf: &[u8], pos: &mut usize) -> u8 {
    let byte = buf[*pos];
    *pos += 1;
    byte
}

fn main() {
    let mut p = Parser { buf: vec![10, 20, 30], pos: 0 };
    // Direct field access gives disjoint borrows — compiles fine
    let b = advance(&p.buf, &mut p.pos);
    println!("{b}"); // 10
}

use tokio_metrics::TaskMonitor;
use std::time::Duration;

#[tokio::main]
async fn main() {
    let monitor = TaskMonitor::new();

    tokio::spawn({
        let monitor = monitor.clone();
        async move {
            for interval in monitor.intervals() {
                println!("mean_poll: {:?}", interval.mean_poll_duration);
                println!("slow_poll_ratio: {:.4}", interval.slow_poll_ratio);
                println!("dropped: {}", interval.dropped_count);
                tokio::time::sleep(Duration::from_secs(5)).await;
            }
        }
    });

    monitor.instrument(do_work()).await;
}

async fn do_work() {
    tokio::time::sleep(Duration::from_millis(120)).await;
}
